sys_ws_operation.operation_script:
(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {

    var datesParam = request.queryParams.dates;
    if (!datesParam) {
        response.setStatus(400);
        response.setBody({ error: 'dates query param required (comma-separated YYYY-MM-DD)' });
        return;
    }

    var dates = datesParam.toString().split(',');
    var availability = new x_608645_my_comp_0.LessonAvailability();

    var startHours = [9, 10, 11, 13];
    var slots = [];

    function pad(n) { return n < 10 ? '0' + n : '' + n; }

    for (var d = 0; d < dates.length; d++) {
        var dateStr = dates[d].trim();
        for (var h = 0; h < startHours.length; h++) {
            var s = new GlideDateTime();
            s.setDisplayValue(dateStr + ' ' + pad(startHours[h]) + ':00:00');
            var e = new GlideDateTime(s);
            e.addSeconds(3600);
            slots.push({
                date:       dateStr,
                label:      pad(startHours[h]) + ':00 - ' + pad(startHours[h] + 1) + ':00',
                startValue: s.getValue(),
                endValue:   e.getValue(),
                available:  availability.isSlotAvailable(s.getValue(), e.getValue())
            });
        }
    }

    response.setStatus(200);
    response.setBody({
        slots:         slots,
        alreadyBooked: availability.hasStudentBookedThisWeek(gs.getUserID())
    });

})(request, response);
